// recoverabilityClient is one client's slice of the fleet KPI.
type recoverabilityClient struct {
	Client         string  `json:"client"`
	Agents         int     `json:"agents"`
	Recoverable    int     `json:"recoverable"`
	RecoverablePct float64 `json:"recoverablePct"`
}

// recoverabilityReport is the fleet-wide recoverable-percentage KPI.
type recoverabilityReport struct {
	TotalAgents        int                    `json:"totalAgents"`
	Recoverable        int                    `json:"recoverable"`
	RecoverablePct     float64                `json:"recoverablePct"`
	ScreenshotVerified int                    `json:"screenshotVerified"`
	Fresh              int                    `json:"fresh"`
	FailedScreenshot   int                    `json:"failedScreenshotOnly"`
	StaleOnly          int                    `json:"staleOnly"`
	FailedBoth         int                    `json:"failedBoth"`
	FreshDays          int                    `json:"freshDays"`
	PerClient          []recoverabilityClient `json:"perClient"`
	Note               string                 `json:"note,omitempty"`
}

// recoverabilityVerdict classifies one agent into the KPI quadrants.
// An agent is recoverable when its latest recovery point is BOTH fresh
// (last snapshot within freshDays) AND screenshot-verified bootable.
func recoverabilityVerdict(screenshotOK bool, lastSnapshot, cutoff int64) (recoverable, fresh bool) {
	fresh = lastSnapshot >= cutoff && lastSnapshot > 0
	return screenshotOK && fresh, fresh
}

// pp:data-source local
func newNovelRecoverabilityCmd(flags *rootFlags) *cobra.Command {
	var flagFreshDays int
	var dbPath string

	cmd := &cobra.Command{
		Use:   "recoverability",
		Short: "One headline KPI: the percentage of fleet agents whose latest recovery point is fresh and screenshot-verified bootable",
		Long: strings.Trim(`
Use this command for the single fleet-wide recoverable-% KPI.
Do NOT use it to list which agents failed; use 'screenshots' (bootability)
or 'stale-backups' (recency) instead.

An agent counts as recoverable when its last local snapshot is within
--fresh-days AND its last boot-verification screenshot passed. Archived
agents are excluded. The per-client breakdown shows which client drags
the fleet number down.`, "\n"),
		Example: strings.Trim(`
  # The morning headline number
  datto-bcdr-cli recoverability --json

  # Stricter freshness bar for tight-RPO fleets
  datto-bcdr-cli recoverability --fresh-days 1 --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would compute the fleet recoverability KPI from the local store")
				return nil
			}
			if err := validateDataSourceStrategy(flags, "local"); err != nil {
				return err
			}
			if dbPath == "" {
				dbPath = defaultDBPath("datto-bcdr-cli")
			}
			db, err := nvOpenStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening database: %w", err)
			}
			defer db.Close()

			if !hintIfUnsynced(cmd, db, "agent") {
				hintIfStale(cmd, db, "agent", flags.maxAge)
			}

			cutoff := time.Now().Unix() - int64(flagFreshDays)*86400

			rows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(data,'$.clientCompanyName'), ''),
					json_extract(data,'$.lastScreenshotAttemptStatus'),
					json_extract(data,'$.lastSnapshot'),
					json_extract(data,'$.isArchived')
				FROM "agent"`)
			if err != nil {
				return fmt.Errorf("querying agents: %w", err)
			}
			defer rows.Close()

			report := recoverabilityReport{FreshDays: flagFreshDays, PerClient: make([]recoverabilityClient, 0)}
			perClient := map[string]*recoverabilityClient{}
			clientOrder := []string{}
			for rows.Next() {
				var (
					client       string
					screenshotOK sql.NullBool
					lastSnapshot sql.NullInt64
					isArchived   sql.NullBool
				)
				if err := rows.Scan(&client, &screenshotOK, &lastSnapshot, &isArchived); err != nil {
					return fmt.Errorf("scanning agent: %w", err)
				}
				// Archived agents are intentionally retired; they don't count
				// against (or toward) the fleet's recoverability.
				if isArchived.Valid && isArchived.Bool {
					continue
				}

				snap := int64(0)
				if lastSnapshot.Valid {
					snap = lastSnapshot.Int64
				}
				shotOK := screenshotOK.Valid && screenshotOK.Bool
				recoverable, fresh := recoverabilityVerdict(shotOK, snap, cutoff)

				report.TotalAgents++
				if shotOK {
					report.ScreenshotVerified++
				}
				if fresh {
					report.Fresh++
				}
				switch {
				case recoverable:
					report.Recoverable++
				case fresh && !shotOK:
					report.FailedScreenshot++
				case !fresh && shotOK:
					report.StaleOnly++
				default:
					report.FailedBoth++
				}

				c, ok := perClient[client]
				if !ok {
					c = &recoverabilityClient{Client: client}
					perClient[client] = c
					clientOrder = append(clientOrder, client)
				}
				c.Agents++
				if recoverable {
					c.Recoverable++
				}
			}
			if err := rows.Err(); err != nil {
				return fmt.Errorf("iterating agents: %w", err)
			}

			if report.TotalAgents > 0 {
				report.RecoverablePct = math.Round(float64(report.Recoverable)/float64(report.TotalAgents)*1000) / 10
			} else {
				report.Note = "no synced agents found; run 'datto-bcdr-cli sync' first"
			}
			for _, name := range clientOrder {
				c := perClient[name]
				if c.Agents > 0 {
					c.RecoverablePct = math.Round(float64(c.Recoverable)/float64(c.Agents)*1000) / 10
				}
				report.PerClient = append(report.PerClient, *c)
			}
			// Worst clients first — the ones dragging the KPI down.
			sort.SliceStable(report.PerClient, func(i, j int) bool {
				if report.PerClient[i].RecoverablePct != report.PerClient[j].RecoverablePct {
					return report.PerClient[i].RecoverablePct < report.PerClient[j].RecoverablePct
				}
				return report.PerClient[i].Client < report.PerClient[j].Client
			})

			return flags.printJSON(cmd, report)
		},
	}
	cmd.Flags().IntVar(&flagFreshDays, "fresh-days", 1, "An agent's last local snapshot must be within N days to count as fresh")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (defaults to standard location)")
	return cmd
}
